import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { Container, Typography, List, CircularProgress, Alert, Paper } from '@mui/material';
import { Link } from 'react-router-dom';
import { ListItem, ListItemText, ListItemSecondaryAction, IconButton } from '@mui/material';
import ThumbUpIcon from '@mui/icons-material/ThumbUp';
import ThumbDownIcon from '@mui/icons-material/ThumbDown';

export default function Questions() {
  const [questions, setQuestions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    axios.get('http://localhost:8080/api/questions')
      .then(res => {
        setQuestions(res.data);
        setLoading(false);
      })
      .catch(err => {
        let msg = 'Không thể tải danh sách câu hỏi';
        if (err.response && err.response.data && err.response.data.error) {
          msg += `: ${err.response.data.error}`;
        } else if (err.message) {
          msg += `: ${err.message}`;
        }
        setError(msg);
        setLoading(false);
      });
  }, []);

  if (loading) return <Container sx={{mt:4}}><CircularProgress /></Container>;
  if (error) return <Container sx={{mt:4}}><Alert severity="error">{error}</Alert></Container>;

  return (
    <Container maxWidth="md" sx={{mt:4}}>
      <Paper elevation={3} sx={{p:3}}>
        <Typography variant="h4" gutterBottom>Danh sách câu hỏi</Typography>
        <List>
          {questions.map((q) => (
            <ListItem key={q.id || q._id} divider button component={Link} to={`/questions/${q.id || q._id}`} alignItems="flex-start">
              <ListItemText
                primary={q.title}
                secondary={
                  <>
                    <Typography component="span" variant="body2" color="text.secondary">
                      Người đăng: {q.userName || 'Ẩn danh'}
                    </Typography>
                    <br />
                    <Typography component="span" variant="body2" color="text.secondary">
                      Upvote: {q.upvote || 0} | Downvote: {q.downvote || 0}
                    </Typography>
                  </>
                }
              />
              <ListItemSecondaryAction>
                <IconButton edge="end" aria-label="upvote" disabled>
                  <ThumbUpIcon fontSize="small" />
                </IconButton>
                <IconButton edge="end" aria-label="downvote" disabled>
                  <ThumbDownIcon fontSize="small" />
                </IconButton>
              </ListItemSecondaryAction>
            </ListItem>
          ))}
        </List>
      </Paper>
    </Container>
  );
}
